        const utils = optimizely.get('utils');

const image = extension.image;
const imageSize = extension.image_size;
const toasterColor = extension.toaster_color;
const headlineText = extension.headline_text;
const headlineFontFamily = extension.headline_font_family;
const headlineFontSize = extension.headline_font_size;
const headlineFontWeight = extension.headline_font_weight;
const headlineFontColor = extension.headline_font_color;
const headlineLineHeight = extension.headline_line_height;

const buttonColor = extension.button_color;
const buttonText = extension.button_text;
const buttonFontFamily = extension.button_font_family;
const buttonFontSize = extension.button_font_size;
const buttonFontWeight = extension.button_font_weight;
const buttonFontColor = extension.button_font_color;
const buttonLink = extension.button_link;
const borderColor = extension.border_color;
const borderWeight = extension.border_weight;

// ✅ HARD-CODED CLOSE ICON URL
const closeIcon = "https://images.mattel.net/mattel-dtc-ag/image/upload/v1773875407/AG%20Site%20Assets/fdlqpzgz7nmmnzwpjznx.svg";

const page = extension.page_visit;
const timing = extension.timing * 1000;
const frequency = extension.frequency;

const txtPosition = extension.text_position;
const btnPosition = extension.button_position;

const styleSheet = document.createElement('style');
styleSheet.textContent = `
.bcToaster:not(.opt) {
  display: none !important;
}
.bcToaster {
  visibility: visible;
  bottom: 20px;
  right: 0px;
  display: block;
  position: fixed;
  z-index: 999;
}

.optToasterContent > div {
  position: relative !important;
  background-color: ${toasterColor} !important;
  background-size: contain !important;
  border: ${borderWeight} solid ${borderColor} !important;
  box-shadow: 6px 6px 14px 0 rgba(0, 0, 0, 0.2) !important;
  display: flex !important;
  flex-direction: row !important;
  height: 120px !important;
  width: 340px !important;
  align-items: center !important;
  border-radius: 2px !important;
  overflow: hidden !important;
}

.bcCloseWrapper {
  position: absolute !important;
  top: 6px !important;
  right: 6px !important;
  width: 20px !important;
  height: 20px !important;
  cursor: pointer !important;
  z-index: 2 !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
}

.bcCloseWrapper img {
  width: 20px !important;
  height: 20px !important;
  display: block !important;
}

.optToasterContent .img_container {
  flex: 1 !important;
  width: 100% !important;
  height: 100% !important;
  max-height: 100px !important;
  max-width: ${imageSize === 'default' ? '120px' : '150px'} !important;
  text-align: center !important;
  padding: 0 10px !important;
  display: flex !important;
  align-items: center !important;
}

.optToasterContent .text_container {
  flex: 1 !important;
  display: flex !important;
  align-items: flex-start !important;
  margin-left: 0 !important;
  flex-direction: column !important;
  justify-content: center !important;
  padding-right: 28px !important;
}

.optToasterContent > div > div p {
  font-family: ${headlineFontFamily} !important;
  font-size: ${headlineFontSize} !important;
  font-weight: ${headlineFontWeight} !important;
  color: ${headlineFontColor} !important;
  line-height: ${headlineLineHeight}px !important;
  margin: 0 0 0.8125rem !important;
  text-align: left !important;
  margin-right: 20px !important;
}

.optToasterContent a {
  background-color: ${buttonColor} !important;
  font-family: ${buttonFontFamily} !important;
  font-size: ${buttonFontSize} !important;
  font-weight: ${buttonFontWeight} !important;
  color: ${buttonFontColor} !important;
  display: inline-block !important;
  padding: 10px 12px 12px !important;
  border-radius: 6px !important;
  text-decoration: none !important;
  margin-right: 20px !important;
}

${txtPosition === 'center'
    ? '.text_container p { padding-inline: 10px; }'
    : txtPosition === 'right'
      ? '.text_container p { padding-left: 30px; }'
      : ''}

.text_container a {
  align-self: ${btnPosition === 'left' ? 'flex-start' : btnPosition === 'center' ? 'center' : 'flex-end'}
}
`;
document.head.appendChild(styleSheet);

const toaster = `
  <div class="bcToaster opt">
    <div class="optToasterContent">
      <div>
        <div class="bcCloseWrapper" aria-label="Close dialog" role="button" tabindex="0">
          <img class="bcCloseIcon" src="${closeIcon}" alt="Close dialog" />
        </div>

        <div class="img_container">
          <img alt="img" style="max-height:100px;" src="${image}">
        </div>

        <div class="text_container">
          <p>${headlineText}</p>
          <a href="${buttonLink}">
            <strong>${buttonText}</strong>
          </a>
        </div>
      </div>
    </div>
  </div>
`;

const setToaster = () => {
  const timeout = setTimeout(() => {
    document.querySelector('body').insertAdjacentHTML('beforeend', toaster);

    const closeEl = document.querySelector('.bcCloseWrapper');
    if (closeEl) {
      closeEl.addEventListener('click', () => {
        const toasterEl = document.querySelector('.bcToaster.opt');
        if (toasterEl) {
          toasterEl.style = 'display: none !important';
        }

        document.cookie = "GlobalToaster=shown; expires=Wed, 31 Dec 2025 12:00:00 utc; path=/; domain=americangirl.com";
      });

      closeEl.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          closeEl.click();
        }
      });
    }

    clearTimeout(timeout);
  }, timing);
};

utils.waitForElement('body:not(.opt)').then(function (body) {
  body.classList.add('opt');

  let sessionPageCount = parseInt(sessionStorage.getItem('sessionPageCount') || '0', 10);
  sessionPageCount += 1;
  sessionStorage.setItem('sessionPageCount', sessionPageCount);

  function getCookieByPattern(pattern) {
    const regex = new RegExp(`(^|;\\s*)(${pattern})=([^;]*)`);
    const match = document.cookie.match(regex);
    return match ? { name: match[2], value: decodeURIComponent(match[3]) } : null;
  }

  if (!getCookieByPattern("GlobalToaster")) {
    if (page === '2') {
      utils.waitUntil(() => sessionPageCount >= 2 && sessionPageCount <= frequency + 1).then(setToaster);
    } else {
      utils.waitUntil(() => sessionPageCount >= 1 && sessionPageCount <= frequency).then(setToaster);
    }
  }
});
